import React from 'react';
import { ChevronUp, ChevronDown, History, TrendingUp, TrendingDown, Minus } from 'lucide-react';
import { Hand, Winner, Result } from '../types';

interface HistoryListProps {
  hands: Hand[];
  isExpanded: boolean;
  onToggle: () => void;
}

const HistoryList: React.FC<HistoryListProps> = ({ hands, isExpanded, onToggle }) => {
  // We want to show the newest hands at the top of the list
  const reversedHands = [...hands].reverse();

  return (
    <div 
      className={`flex-none bg-zinc-900/95 backdrop-blur-md border-t border-zinc-800 flex flex-col transition-all duration-300 ease-in-out shadow-[0_-10px_15px_-3px_rgba(0,0,0,0.4)] z-20 ${
        isExpanded ? 'h-[260px]' : 'h-[92px]'
      }`}
    >
      {/* Header with Handle */}
      <div 
        onClick={onToggle} 
        className="relative px-4 pt-3 pb-2 border-b border-zinc-800 bg-zinc-900 flex justify-between items-center cursor-pointer hover:bg-zinc-800/80 transition-colors group"
      >
        {/* Drag Handle UI */}
        <div className="absolute top-1.5 left-1/2 -translate-x-1/2 w-8 h-1 bg-zinc-800 rounded-full group-hover:bg-zinc-700 transition-colors" />

        <div className="flex items-center space-x-2 text-zinc-400 group-hover:text-zinc-300 mt-1">
          <History className="w-4 h-4" />
          <span className="text-[10px] font-bold uppercase tracking-widest">Hand History</span>
          <span className="text-[10px] text-zinc-600 font-mono ml-1">({hands.length})</span>
        </div>
        <button className="text-zinc-500 group-hover:text-zinc-300 mt-1">
          {isExpanded ? <ChevronDown className="w-4 h-4" /> : <ChevronUp className="w-4 h-4" />}
        </button>
      </div>

      {/* List */}
      <div className={`flex-1 p-1 space-y-1 custom-scroll ${isExpanded ? 'overflow-y-auto' : 'overflow-hidden'}`}>
        {hands.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-zinc-600 text-xs italic space-y-2 py-4">
            <span>Waiting for first hand...</span>
          </div>
        ) : (
          reversedHands.map((h) => (
            <div 
              key={h.id} 
              className="grid grid-cols-12 gap-2 items-center p-2 rounded hover:bg-zinc-800/50 text-sm border border-transparent hover:border-zinc-800 transition-colors animate-in slide-in-from-bottom-2 h-[40px]"
            >
              {/* ID */}
              <div className="col-span-1 text-zinc-500 font-mono text-[10px]">#{h.id}</div>

              {/* Scores */}
              <div className="col-span-4 flex items-center space-x-2 font-mono">
                {h.winner === Winner.PLAYER && (
                  <>
                    <span className="font-bold text-blue-500">P:{h.playerScore}</span>
                    <span className="text-zinc-600">-</span>
                    <span className="font-bold text-zinc-600">B:{h.bankerScore}</span>
                  </>
                )}
                {h.winner === Winner.BANKER && (
                  <>
                    <span className="font-bold text-zinc-600">P:{h.playerScore}</span>
                    <span className="text-zinc-600">-</span>
                    <span className="font-bold text-red-500">B:{h.bankerScore}</span>
                  </>
                )}
                {h.winner === Winner.TIE && (
                  <>
                    <span className="font-bold text-zinc-500">P:{h.playerScore}</span>
                    <span className="text-zinc-600">-</span>
                    <span className="font-bold text-zinc-500">B:{h.bankerScore}</span>
                  </>
                )}
                <span className="text-[10px] font-bold text-amber-500 bg-amber-500/10 border border-amber-500/20 px-1.5 py-0.5 rounded ml-1">
                  Δ{h.delta}
                </span>
              </div>

              {/* Prediction */}
              <div className="col-span-3 text-center">
                {h.prediction ? (
                  <div className="flex items-center justify-center space-x-1">
                    <span className="text-zinc-600 text-[9px] uppercase tracking-tighter">Bet:</span>
                    <span className={`font-bold text-[10px] px-1.5 py-0.5 rounded ${
                      h.prediction === Winner.PLAYER ? 'bg-blue-900/30 text-blue-400' : 'bg-red-900/30 text-red-400'
                    }`}>
                      {h.prediction === Winner.PLAYER ? 'P' : 'B'}
                    </span>
                  </div>
                ) : (
                  <span className="text-zinc-700">-</span>
                )}
              </div>

              {/* Result Icon */}
              <div className="col-span-2 flex justify-center">
                {h.result === Result.WIN && (
                  <div className="flex items-center text-emerald-500 text-[10px] font-bold">
                    <TrendingUp className="w-3 h-3 mr-1" /> Win
                  </div>
                )}
                {h.result === Result.LOSS && (
                  <div className="flex items-center text-rose-500 text-[10px] font-bold">
                    <TrendingDown className="w-3 h-3 mr-1" /> Loss
                  </div>
                )}
                {h.result === Result.PUSH && (
                  <div className="flex items-center text-zinc-500 text-[10px]">
                    <Minus className="w-3 h-3 mr-1" /> Push
                  </div>
                )}
              </div>

              {/* Running Total */}
              <div className={`col-span-2 text-right font-mono font-bold ${
                h.runningTotal > 0 ? 'text-emerald-400' : h.runningTotal < 0 ? 'text-rose-400' : 'text-zinc-400'
              }`}>
                {h.runningTotal > 0 ? '+' : ''}{h.runningTotal}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default HistoryList;

import React, { useState, useEffect } from 'react';
import { Check, X } from 'lucide-react';

interface KeypadProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (p: number, b: number) => void;
}

const Keypad: React.FC<KeypadProps> = ({ isOpen, onClose, onSubmit }) => {
  const [input, setInput] = useState<string>('');

  useEffect(() => {
    if (isOpen) setInput('');
  }, [isOpen]);

  if (!isOpen) return null;

  const handlePress = (num: number) => {
    if (input.length < 2) {
      setInput(prev => prev + num.toString());
    }
  };

  const handleBackspace = () => setInput(prev => prev.slice(0, -1));

  const pScore = input[0] ? parseInt(input[0]) : null;
  const bScore = input[1] ? parseInt(input[1]) : null;

  const isComplete = input.length === 2;
  const isTie = isComplete && pScore === bScore;
  const canSubmit = isComplete && !isTie;

  const handleSubmit = () => {
    if (canSubmit && pScore !== null && bScore !== null) {
      onSubmit(pScore, bScore);
    }
  };

  return (
    <>
      <div className="fixed inset-0 z-40 bg-black/20 backdrop-blur-[1px]" onClick={onClose} />
      <div className="fixed top-20 right-2 sm:right-4 z-50 w-full max-w-[340px] bg-zinc-900 border border-zinc-700 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in fade-in slide-in-from-top-4 duration-200">
        {/* Header */}
        <div className="flex justify-between items-center p-3 border-b border-zinc-800 bg-zinc-800/50">
          <h2 className="text-sm font-bold text-zinc-300 uppercase tracking-wider">Input Result</h2>
          <button onClick={onClose} className="p-1.5 hover:bg-zinc-700 rounded-full transition-colors text-zinc-400">
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Display */}
        <div className="bg-zinc-950 p-8 flex justify-center items-center border-b border-zinc-800">
          <div className="flex items-center space-x-12 text-5xl font-mono">
            <div className="flex flex-col items-center">
              <span className={`font-bold transition-colors duration-200 ${pScore !== null ? 'text-blue-500' : 'text-zinc-700'}`}>
                {pScore ?? 0}
              </span>
            </div>
            <span className="text-zinc-700 font-thin">:</span>
            <div className="flex flex-col items-center">
              <span className={`font-bold transition-colors duration-200 ${bScore !== null ? 'text-red-500' : 'text-zinc-700'}`}>
                {bScore ?? 0}
              </span>
            </div>
          </div>
        </div>

        {/* Buttons */}
        <div className="p-3 grid grid-cols-3 gap-2 bg-zinc-900">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((num) => (
            <button
              key={num}
              onClick={() => handlePress(num)}
              className="h-14 text-2xl font-medium bg-zinc-800 rounded-lg hover:bg-zinc-700 active:bg-zinc-600 text-zinc-200 transition-colors"
            >
              {num}
            </button>
          ))}

          <button onClick={handleBackspace} className="h-14 flex items-center justify-center bg-zinc-800/50 rounded-lg hover:bg-zinc-700/50 text-red-400 transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M19 12H5"/><path d="m12 19-7-7 7-7"/>
            </svg>
          </button>

          <button
            onClick={() => handlePress(0)}
            className="h-14 text-2xl font-medium bg-zinc-800 rounded-lg hover:bg-zinc-700 active:bg-zinc-600 text-zinc-200 transition-colors"
          >
            0
          </button>

          <button
            onClick={handleSubmit}
            disabled={!canSubmit}
            className={`h-14 flex items-center justify-center rounded-lg font-bold transition-all shadow-lg ${
              canSubmit 
                ? 'bg-emerald-600 hover:bg-emerald-500 text-white shadow-emerald-900/20 active:scale-95' 
                : 'bg-zinc-800/50 text-zinc-600 cursor-not-allowed'
            }`}
          >
            {isTie ? (
              <span className="text-xs font-bold text-rose-500">NO TIE</span>
            ) : (
              <Check className="w-6 h-6" />
            )}
          </button>
        </div>
      </div>
    </>
  );
};

export default Keypad;

import React, { useState, useEffect } from 'react';
import { RefreshCw, Menu } from 'lucide-react';
import StrategyChart from './components/StrategyChart';
import Keypad from './components/Keypad';
import HistoryList from './components/HistoryList';
import { Hand, Winner, Result } from './types';

const App: React.FC = () => {
  // -- State --
  const [hands, setHands] = useState<Hand[]>([]);
  const [nextPrediction, setNextPrediction] = useState<Winner | null>(null);

  // UI State
  const [isKeypadOpen, setIsKeypadOpen] = useState(false);
  const [isHistoryExpanded, setIsHistoryExpanded] = useState(false);
  const [isResetModalOpen, setIsResetModalOpen] = useState(false);

  // -- Logic --

  const handleScoreSubmit = (playerScore: number, bankerScore: number) => {
    // 1. Determine Actual Winner
    let actualWinner = Winner.TIE;
    if (playerScore > bankerScore) actualWinner = Winner.PLAYER;
    else if (bankerScore > playerScore) actualWinner = Winner.BANKER;

    // 2. Evaluate Previous Prediction against actual outcome
    let result = Result.PENDING;
    let unitsChanged = 0;

    if (nextPrediction) {
      if (actualWinner === Winner.TIE) {
        result = Result.PUSH;
        unitsChanged = 0;
      } else if (actualWinner === nextPrediction) {
        result = Result.WIN;
        unitsChanged = 1;
      } else {
        result = Result.LOSS;
        unitsChanged = -1;
      }
    } else {
      // First hand or no prediction
      result = Result.PUSH; 
    }

    // 3. Calculate Running Total
    const lastTotal = hands.length > 0 ? hands[hands.length - 1].runningTotal : 0;
    const newTotal = lastTotal + unitsChanged;

    // 4. Strategy for NEXT hand (The "Delta" Strategy)
    const delta = Math.abs(playerScore - bankerScore);
    let strategyPrediction: Winner | null = null;

    if (actualWinner !== Winner.TIE) {
      if (delta >= 5) {
        // High delta: Trend Follow
        strategyPrediction = actualWinner; 
      } else {
        // Low delta: Chop (Opposite)
        strategyPrediction = actualWinner === Winner.PLAYER ? Winner.BANKER : Winner.PLAYER;
      }
    } else {
      // Tie: Hold previous prediction
      strategyPrediction = nextPrediction;
    }

    const newHand: Hand = {
      id: hands.length + 1,
      playerScore,
      bankerScore,
      winner: actualWinner,
      prediction: nextPrediction,
      result,
      runningTotal: newTotal,
      delta
    };

    setHands(prev => [...prev, newHand]);
    setNextPrediction(strategyPrediction);
    setIsKeypadOpen(false);
  };

  const handleReset = () => {
    setHands([]);
    setNextPrediction(null);
    setIsResetModalOpen(false);
  };

  // -- Render Helpers --

  const getNextBetIndicator = () => {
    if (nextPrediction === Winner.PLAYER) {
      return (
        <div className="flex items-center justify-center w-12 h-12 rounded-xl border-2 shadow-[0_0_15px_rgba(59,130,246,0.2)] bg-blue-500/10 border-blue-500 text-blue-500 transition-all duration-300">
          <span className="text-2xl font-black">P</span>
        </div>
      );
    } 
    if (nextPrediction === Winner.BANKER) {
      return (
        <div className="flex items-center justify-center w-12 h-12 rounded-xl border-2 shadow-[0_0_15px_rgba(239,68,68,0.2)] bg-red-500/10 border-red-500 text-red-500 transition-all duration-300">
          <span className="text-2xl font-black">B</span>
        </div>
      );
    }
    return (
      <div className="flex items-center justify-center w-12 h-12 rounded-xl border-2 bg-zinc-800/50 border-zinc-700 text-zinc-700 transition-all duration-300">
        <span className="text-2xl font-black">-</span>
      </div>
    );
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-zinc-950 text-zinc-100">

      {/* HEADER */}
      <header className="flex-none h-16 bg-zinc-900 border-b border-zinc-800 flex items-center justify-between px-4 z-30 relative shadow-md">
        <div className="flex items-center space-x-3">
          <img src="logo.svg" alt="D5 Logo" className="w-8 h-8 rounded-lg shadow-inner" />
          <h1 className="text-lg font-bold tracking-tight text-zinc-300 hidden sm:block">D5 Navigator</h1>
        </div>

        {/* Center Indicator */}
        <div className="absolute left-1/2 top-1/2 transform -translate-x-1/2 -translate-y-1/2 flex items-center space-x-3">
          <span className="text-zinc-500 text-xs font-bold uppercase tracking-wider hidden sm:block">Next Bet:</span>
          {getNextBetIndicator()}
        </div>

        {/* Actions */}
        <div className="flex items-center space-x-3">
          <button 
            onClick={() => setIsResetModalOpen(true)}
            className="p-2 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded-lg transition-colors"
            title="Reset Game"
          >
            <RefreshCw className="w-5 h-5" />
          </button>
          <button 
            onClick={() => setIsKeypadOpen(true)}
            className={`p-2 rounded-lg transition-all active:scale-95 ${
              isKeypadOpen 
                ? 'bg-zinc-800 text-white' 
                : 'text-zinc-500 hover:text-white hover:bg-zinc-800'
            }`}
          >
            <Menu className="w-6 h-6" />
          </button>
        </div>
      </header>

      {/* MAIN CONTENT */}
      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Chart Area */}
        <div className="flex-1 min-h-0 p-4 bg-zinc-950 relative">
          <StrategyChart hands={hands} />
        </div>

        {/* History Area */}
        <HistoryList 
          hands={hands} 
          isExpanded={isHistoryExpanded} 
          onToggle={() => setIsHistoryExpanded(!isHistoryExpanded)} 
        />
      </main>

      {/* MODALS */}
      <Keypad 
        isOpen={isKeypadOpen} 
        onClose={() => setIsKeypadOpen(false)} 
        onSubmit={handleScoreSubmit} 
      />

      {/* Reset Confirmation */}
      {isResetModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/70 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-zinc-900 border border-zinc-800 p-6 rounded-2xl shadow-2xl max-w-sm w-full mx-4">
            <div className="flex items-center space-x-3 mb-4 text-amber-500">
              <RefreshCw className="w-6 h-6" />
              <h3 className="text-lg font-bold text-white">Reset Game Data?</h3>
            </div>
            <p className="text-zinc-400 text-sm mb-6 leading-relaxed">
              This will clear all hand history, reset your performance chart, and delete your current session statistics. This action cannot be undone.
            </p>
            <div className="flex justify-end space-x-3">
              <button 
                onClick={() => setIsResetModalOpen(false)} 
                className="px-4 py-2 rounded-lg text-sm font-medium text-zinc-300 hover:bg-zinc-800 transition-colors"
              >
                Cancel
              </button>
              <button 
                onClick={handleReset} 
                className="px-4 py-2 rounded-lg text-sm font-bold bg-rose-600 hover:bg-rose-500 text-white shadow-lg shadow-rose-900/20 transition-all hover:scale-105 active:scale-95"
              >
                Reset Everything
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
